  `decklist_id` int DEFAULT NULL,
  `client_id` int DEFAULT NULL,
  `user_id` int DEFAULT NULL,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `url` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `rank` smallint NOT NULL,
  `participants` smallint NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `usercard_index` (`decklist_id`,`client_id`,`name`,`rank`),
  KEY `IDX_A769DE27F4E9531B` (`decklist_id`),
  KEY `IDX_A769DE2719EB6921` (`client_id`),
  KEY `IDX_A769DE27A76ED395` (`user_id`),
  CONSTRAINT `FK_A769DE2719EB6921` FOREIGN KEY (`client_id`) REFERENCES `client` (`id`),
  CONSTRAINT `FK_A769DE27A76ED395` FOREIGN KEY (`user_id`) REFERENCES `user` (`id`),
  CONSTRAINT `FK_A769DE27F4E9531B` FOREIGN KEY (`decklist_id`) REFERENCES `decklist` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
